INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-10ced7e2-moex-00901', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「我靜坐水湄一隅，瞧！蘆葦□□著身子，頂著一頭□□般的髮。是由於負荷了過重的鄉思而壓彎了脊樑？ 是因著朝夕守望而愁白了頭嚒？」根據文意，文中的□□依序應是：', '["挺立／青絲", "傾斜／蓬草", "佝僂／銀絲", "搖曳／枯柳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00902', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列題辭用語，何者適當？', '["「于歸之喜」：慶賀遷居", "「瓜瓞延祥」：慶賀生孫", "「母儀足式」：慶賀女壽", "「弄璋誌喜」：慶賀生女"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00903', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「來自日本東京的鐵道迷藤井英樹，熱愛蒸汽火車。四年前來臺，發現臺灣的蒸汽火車竟然跟日本的一樣， 讓他因此著迷，四年來已造訪臺灣五十次！藤井說，臺鐵修復很多蒸汽火車，因此特別喜歡臺鐵。今年六月 起，連續三個週六，『仲夏寶島號』由玉里開到臺東，藤井英樹特別安排三天來臺灣搭乘。」依據上文，下 列敘述何者最符合文意？', '["臺灣的蒸汽火車吸引日本鐵道迷", "藤井英樹因為喜歡臺灣，特別來臺五十次", "自六月起臺鐵每週六皆開出「仲夏寶島號」", "藤井英樹因為「仲夏寶島號」而熱愛蒸汽火車"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00904', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列選項的情感「對象」，並非「朋友」的是：', '["布衣之交不可忘，金蘭之誼常在心", "遙知兄弟登高處，遍插茱萸少一人", "若知四海皆兄弟，何處相逢非故人", "桃花潭水深千尺，不及汪倫送我情"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00905', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '簾外雨潺潺，春意闌珊。羅衾不耐五更寒。夢裡不知身是客，一晌貪歡。獨自莫凭欄，無限江山。別時容易 見時難。流水落花春去也，天上人間（李煜〈浪淘沙〉）。其中「夢裡不知身是客，一晌貪歡」指的是：', '["只有夜夜笙歌，醉生夢死方能排遣苦悶", "貶謫他鄉無可奈何，只好貪圖片刻歡愉", "羈旅漂泊生涯，把人生當作虛幻的夢境", "現實生活苦悶難捱，貪戀夢中短暫歡樂"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00906', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「鳥飛到雲中去／鳥群中少了你／太陽落到山稜後／山群中少了你／是的，少了你這風景又怎能印得成記 憶」，下列何者最接近本詩旨意？', '["繁華落盡見真淳", "鳥盡良弓勢必藏", "有了你，生命才有意義", "有遺憾，也是一種美麗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00907', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '陳述古密直知建州浦城縣日，有人失物，捕得，莫知的為盜者。述古乃紿之曰：「某廟有一鐘，能辨盜至靈。」 使人迎置後閤祠之，引群囚立鐘前，自陳：不為盜者摸之則無聲，為盜者摸之則有聲。述古自率同職禱鐘甚 肅，祭訖，以帷圍之，乃陰使人以墨塗鐘。良久，引囚逐一令引手入帷摸之，出乃驗其手，皆有墨，唯有一 囚無墨。訊之，遂承為盜，蓋恐鐘有聲，不敢摸也（沈括《夢溪筆談》）。文中「述古自率同職禱鐘甚肅」 的主要用意為何？', '["假借鬼神之說，使人心生畏懼", "善用辦案工具，期能事半功倍", "官府例行公事，以求辦案順利", "藉由虔誠敬拜，祈求鬼神助佑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00908', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「我的朋友是一位肖像畫家，生活不好過，朋友紛紛給她忠告。大多數人的建議歸結來講就是：『找份正職 吧。』她對我說：『我本來就有正職啊！我是個畫家，他們難道不明白嗎？』……三年過去了，到目前為止， 我的朋友證明了自己是對的。」下列何者，最符合文意？', '["藝術家可以將個人創作視為正職", "創作與謀生彼此衝突而不能兼顧", "藝術無價不必討論現實薪資問題", "有固定收入才是藝術家謀生之道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00909', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「古人有詩云：『但願此心春長在，須知世上苦人多。』若能時時想到世間多少不如我們、需要我們幫助的 人，那麼成敗得失之念，就容納不下，此心就充滿歡樂了。」下列選項，最接近意旨的是：', '["知足常樂", "簡單就是快樂", "寬容是快樂的來源", "獨樂樂，不如眾樂樂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00910', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「身為埔里農家小子，年輕的洪健智不想待在故鄉務農，高中畢業後便毅然前往臺北晶華飯店學習和式料 理。在緊湊的都會生活裡，他圓了夢，卻也因此錯失了孩子部分的成長時光。『週遭長輩都會說，要讓孩子 在都市成長，才會有競爭力。結果卻是讓孩子的童年只剩學校和安親班。』洪健智談起孩子，回想自己，『我 們小時候在田野裡跑啊跑啊，在溪邊釣魚、原野上焢窯，那才是真的快樂的小時候！』」根據上文，下列選 項何者最符合本文意旨？', '["相較城市生活，家鄉生活步調更適合自己", "競爭力並非一定要在城市才可以培養出來", "童年的時光很重要，希望將快樂還給孩子", "對於年少時期的錯誤選擇，感到後悔不已"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
